{"code": "import json, re, numpy as np, os

# Get the stored data from variables
clinical_var = locals()['var_functions.query_db_144']
mutation_var = locals()['var_functions.query_db_130']

# Load clinical data for female BRCA patients
clinical = json.load(open(clinical_var))

# Get CDH1 mutation participants
cdh1_set = set()
for m in mutation_var:
    if isinstance(m, dict) and 'ParticipantBarcode' in m:
        cdh1_set.add(m['ParticipantBarcode'])

print('Loaded', len(clinical), 'female BRCA patients and', len(cdh1_set), 'CDH1 mutations')

# Build contingency table
tbl = {}
for r in clinical:
    desc = r['Patient_description']
    hist = r['histological_type']
    m = re.search(r'(TCGA-\w+-\w+)', desc)
    if m:
        participant = '-'.join(m.group(1).split('-')[:3])
        if hist not in tbl:
            tbl[hist] = [0, 0]
        if participant in cdh1_set:
            tbl[hist][0] += 1
        else:
            tbl[hist][1] += 1

# Filter by marginal totals > 10
filtered = []
for counts in tbl.values():
    if sum(counts) > 10:
        filtered.append(counts)

# Calculate chi-square
chi2, dof = None, None
if len(filtered) >= 2:
    a = np.array(filtered, dtype=float)
    row, col = a.sum(axis=1), a.sum(axis=0)
    exp = np.outer(row, col) / a.sum()
    chi2 = float(((a - exp) ** 2 / exp).sum())
    dof = int((a.shape[0] - 1) * (a.shape[1] - 1))

result = {
    'chi2_statistic': chi2,
    'degrees_of_freedom': dof,
    'contingency_table': filtered
}

print('__RESULT__:')
print(json.dumps(result))"}
